int dinic(const vector<int>& arr) {
    if (arr.size() < 4) return 0;
    int n = arr[0];
    int m = arr[1];
    int s = arr[2];
    int t = arr[3];

    if (arr.size() < 4 + 3 * m) return 0;

    adj.assign(n, vector<Edge>());
    level.resize(n);
    ptr.resize(n);

    for (int i = 0; i < m; i++) {
        int u = arr[4 + 3 * i];
        int v = arr[4 + 3 * i + 1];
