        a = Edge(v, len(adj[v]), cap)
        b = Edge(u, len(adj[u]), 0)
        adj[u].append(a)
        adj[v].append(b)

    for i in range(m):
        u = arr[4 + 3 * i]
        v = arr[4 + 3 * i + 1]
        cap = arr[4 + 3 * i + 2]
        if 0 <= u < n and 0 <= v < n:
            add_edge(u, v, cap)

    level = [-1] * n
    ptr = [0] * n

    def bfs():
        for i in range(n):
            level[i] = -1
        level[s] = 0
        q = deque([s])
        while q:
            u = q.popleft()
            for e in adj[u]:
                if e.cap - e.flow > 0 and level[e.to] == -1:
                    level[e.to] = level[u] + 1
                    q.append(e.to)
        return level[t] != -1

    def dfs(u, pushed):
        if pushed == 0:
            return 0
        if u == t:
            return pushed

        for cid in range(ptr[u], len(adj[u])):
            ptr[u] = cid
            e = adj[u][cid]
            v = e.to
            if level[u] + 1 != level[v] or e.cap - e.flow == 0:
                continue

            tr = pushed
            if e.cap - e.flow < tr:
                tr = e.cap - e.flow

            pushed_flow = dfs(v, tr)
            if pushed_flow == 0:
                continue

            e.flow += pushed_flow
            adj[v][e.rev].flow -= pushed_flow
            return pushed_flow

        ptr[u] = len(adj[u]) # Fully explored
        return 0

    flow = 0
    while bfs():
        for i in range(n):
            ptr[i] = 0
        while True:
            pushed = dfs(s, float('inf'))
            if pushed == 0:
                break
            flow += pushed

    return flow

use std::collections::VecDeque;
use std::i64;

#[derive(Clone)]
struct Edge {
    to: usize,
    rev: usize,
    cap: i64,
    flow: i64,
}

struct Dinic {
    adj: Vec<Vec<Edge>>,
    level: Vec<i32>,
    ptr: Vec<usize>,
    n: usize,
}

impl Dinic {
    fn new(n: usize) -> Self {
        Dinic {
            adj: vec![Vec::new(); n],
            level: vec![-1; n],
            ptr: vec![0; n],
            n,
        }
    }

    fn add_edge(&mut self, u: usize, v: usize, cap: i64) {
        let rev_u = self.adj[v].len();
        let rev_v = self.adj[u].len();
        self.adj[u].push(Edge { to: v, rev: rev_u, cap, flow: 0 });
        self.adj[v].push(Edge { to: u, rev: rev_v, cap: 0, flow: 0 });
    }

    fn bfs(&mut self, s: usize, t: usize) -> bool {
        self.level.fill(-1);
        self.level[s] = 0;
        let mut q = VecDeque::new();
        q.push_back(s);

        while let Some(u) = q.pop_front() {
            for e in &self.adj[u] {
                if e.cap - e.flow > 0 && self.level[e.to] == -1 {
                    self.level[e.to] = self.level[u] + 1;
                    q.push_back(e.to);
                }
            }
        }
        self.level[t] != -1
    }

    fn dfs(&mut self, u: usize, t: usize, pushed: i64) -> i64 {
        if pushed == 0 {
            return 0;
        }
        if u == t {
            return pushed;
        }

        while self.ptr[u] < self.adj[u].len() {
            let cid = self.ptr[u];
            let v = self.adj[u][cid].to;

            // Need to check conditions before borrowing mutable
            let valid = self.level[u] + 1 == self.level[v] && self.adj[u][cid].cap - self.adj[u][cid].flow > 0;

            if !valid {
                self.ptr[u] += 1;
                continue;
            }

            let tr = pushed.min(self.adj[u][cid].cap - self.adj[u][cid].flow);
            let pushed_flow = self.dfs(v, t, tr);

            if pushed_flow == 0 {
                self.ptr[u] += 1;
                continue;
            }

            self.adj[u][cid].flow += pushed_flow;
            let rev = self.adj[u][cid].rev;
            self.adj[v][rev].flow -= pushed_flow;

            return pushed_flow;
        }
        0
    }
}

pub fn dinic(arr: &[i32]) -> i32 {
    if arr.len() < 4 {
        return 0;
    }
    let n = arr[0] as usize;
    let m = arr[1] as usize;
    let s = arr[2] as usize;
    let t = arr[3] as usize;

    if arr.len() < 4 + 3 * m {
        return 0;
    }

    let mut graph = Dinic::new(n);
    for i in 0..m {
        let u = arr[4 + 3 * i] as usize;
        let v = arr[4 + 3 * i + 1] as usize;
        let cap = arr[4 + 3 * i + 2] as i64;
        if u < n && v < n {
            graph.add_edge(u, v, cap);
        }
    }

    let mut flow = 0;
    while graph.bfs(s, t) {
        graph.ptr.fill(0);
        loop {
            let pushed = graph.dfs(s, t, i64::MAX);
            if pushed == 0 {
                break;
            }
            flow += pushed;
        }
    }

    flow as i32
}

package algorithms.graph.dinic

import java.util.LinkedList
import java.util.Queue
import scala.collection.mutable.ArrayBuffer
import scala.math.min

object Dinic {
  case class Edge(to: Int, rev: Int, cap: Long, var flow: Long)

  def solve(arr: Array[Int]): Int = {
    if (arr.length < 4) return 0
    val n = arr(0)
    val m = arr(1)
    val s = arr(2)
    val t = arr(3)

    if (arr.length < 4 + 3 * m) return 0

    val adj = Array.fill(n)(new ArrayBuffer[Edge])
    for (i <- 0 until m) {
      val u = arr(4 + 3 * i)
      val v = arr(4 + 3 * i + 1)
      val cap = arr(4 + 3 * i + 2).toLong
      if (u >= 0 && u < n && v >= 0 && v < n) {
        val a = Edge(v, adj(v).length, cap, 0)
        val b = Edge(u, adj(u).length, 0, 0)
        adj(u).append(a)
        adj(v).append(b)
      }
    }

    val level = new Array[Int](n)
    val ptr = new Array[Int](n)

    def bfs(): Boolean = {
      java.util.Arrays.fill(level, -1)
      level(s) = 0
      val q: Queue[Int] = new LinkedList()
      q.add(s)

      while (!q.isEmpty) {
        val u = q.poll()
        for (e <- adj(u)) {
          if (e.cap - e.flow > 0 && level(e.to) == -1) {
            level(e.to) = level(u) + 1
            q.add(e.to)
          }
        }
      }
      level(t) != -1
    }

    def dfs(u: Int, pushed: Long): Long = {
      if (pushed == 0) return 0
      if (u == t) return pushed

      while (ptr(u) < adj(u).length) {
        val id = ptr(u)
        val e = adj(u)(id)
        val v = e.to

        if (level(u) + 1 != level(v) || e.cap - e.flow == 0) {
          ptr(u) += 1
        } else {
          val tr = pushed
          val actualPushed = if (e.cap - e.flow < tr) e.cap - e.flow else tr

          val pushedFlow = dfs(v, actualPushed)
          if (pushedFlow == 0) {
            ptr(u) += 1
          } else {
            e.flow += pushedFlow
            adj(v)(e.rev).flow -= pushedFlow
            return pushedFlow
          }
        }
      }
      0
    }

    var flow: Long = 0
    while (bfs()) {
      java.util.Arrays.fill(ptr, 0)
      var pushed: Long = 0
      do {
        pushed = dfs(s, Long.MaxValue)
        flow += pushed
      } while (pushed != 0)
    }

    flow.toInt
  }
}

class Dinic {
    class Edge {
        let to: Int
        let rev: Int
        var cap: Int64
        var flow: Int64

        init(to: Int, rev: Int, cap: Int64) {
            self.to = to
            self.rev = rev
            self.cap = cap
            self.flow = 0
        }
    }

    static func solve(_ arr: [Int]) -> Int {
        if arr.count < 4 { return 0 }
        let n = arr[0]
        let m = arr[1]
        let s = arr[2]
        let t = arr[3]

        if arr.count < 4 + 3 * m { return 0 }

        var adj = [[Edge]](repeating: [], count: n)
        for i in 0..<m {
            let u = arr[4 + 3 * i]
            let v = arr[4 + 3 * i + 1]
            let cap = Int64(arr[4 + 3 * i + 2])
            if u >= 0 && u < n && v >= 0 && v < n {
                let a = Edge(to: v, rev: adj[v].count, cap: cap)
                let b = Edge(to: u, rev: adj[u].count, cap: 0)
                adj[u].append(a)
                adj[v].append(b)
            }
        }

        var level = [Int](repeating: -1, count: n)
        var ptr = [Int](repeating: 0, count: n)

        func bfs() -> Bool {
            level = [Int](repeating: -1, count: n)
            level[s] = 0
            var q = [s]
            var head = 0

            while head < q.count {
                let u = q[head]
                head += 1
                for e in adj[u] {
                    if e.cap - e.flow > 0 && level[e.to] == -1 {
                        level[e.to] = level[u] + 1
                        q.append(e.to)
                    }
                }
            }
            return level[t] != -1
        }

        func dfs(_ u: Int, _ pushed: Int64) -> Int64 {
            if pushed == 0 { return 0 }
            if u == t { return pushed }

            while ptr[u] < adj[u].count {
                let id = ptr[u]
                let e = adj[u][id]
                let v = e.to

                if level[u] + 1 != level[v] || e.cap - e.flow == 0 {
                    ptr[u] += 1
                    continue
                }

                let tr = min(pushed, e.cap - e.flow)
                let pushedFlow = dfs(v, tr)

                if pushedFlow == 0 {
                    ptr[u] += 1
                    continue
                }

                e.flow += pushedFlow
                adj[v][e.rev].flow -= pushedFlow
                return pushedFlow
            }
            return 0
        }

        var flow: Int64 = 0
        while bfs() {
            ptr = [Int](repeating: 0, count: n)
            while true {
                let pushed = dfs(s, Int64.max)
                if pushed == 0 { break }
                flow += pushed
            }
        }

        return Int(flow)
    }
}

class Edge {
  to: number;
